$('#soxlSnapshotForm').addEventListener('submit', async (event) => { event.preventDefault(); const soxl = state.investments.soxl; const subscriptionFeeKrw = investmentNumber($('#soxlSubscriptionFee').value); try { const rate = subscriptionFeeKrw ? await loadUsdKrwRate() : 1; [['principal', 'soxlPrincipal'], ['shares', 'soxlShares'], ['averagePrice', 'soxlAveragePrice']].forEach(([key, input]) => { soxl[key] = investmentNumber($(`#${input}`).value); }); soxl.purchaseAmount = investmentNumber(soxl.shares) * investmentNumber(soxl.averagePrice); soxl.cash = investmentNumber(soxl.principal) - soxl.purchaseAmount; soxl.valuation = investmentNumber(soxl.shares) * marketQuotePrice('SOXL', investmentNumber(soxl.valuation) / Math.max(investmentNumber(soxl.shares), 1)); soxl.subscriptionFeeKrw = subscriptionFeeKrw; soxl.subscriptionFeeUsd = subscriptionFeeKrw ? subscriptionFeeKrw / rate : 0; updateLatestSoxlSnapshot(); persist(); render(); $('#soxlSnapshotDialog').close(); } catch { alert('구독료 환산을 위한 환율을 불러오지 못했어요. 인터넷 연결을 확인한 뒤 다시 시도해주세요.'); } });
$('#soxlTradeForm').addEventListener('submit', (event) => { event.preventDefault(); const soxl = state.investments.soxl; const type = $('#soxlTradeType').value; const shares = investmentNumber($('#soxlTradeShares').value); const price = investmentNumber($('#soxlTradePrice').value); const nextTrade = { id: editingSoxlTradeId || createGoalId(), date: $('#soxlTradeDate').value, type, shares, price, amount: shares * price, note: $('#soxlTradeNote').value.trim() }; if (!shares || !price) return; const existing = editingSoxlTradeId ? soxl.trades.find((item) => item.id === editingSoxlTradeId) : null; const backup = { shares: soxl.shares, averagePrice: soxl.averagePrice, cash: soxl.cash, purchaseAmount: soxl.purchaseAmount, valuation: soxl.valuation }; if (existing && !applySoxlTrade(existing, -1)) { alert('현재 보유 현황과 맞지 않아 이 기록을 수정할 수 없어요. 먼저 이후 거래 또는 현재 현황을 확인해주세요.'); return; } if (!applySoxlTrade(nextTrade)) { Object.assign(soxl, backup); alert('현재 보유 수량보다 많이 매도할 수 없어요.'); return; } if (existing) { removeSoxlTradeSnapshot(existing.id, existing.date); soxl.trades[soxl.trades.findIndex((item) => item.id === existing.id)] = nextTrade; snapshotSoxl(`${nextTrade.date}T12:00:00`); } else { soxl.trades.unshift(nextTrade); snapshotSoxl(`${nextTrade.date}T12:00:00`); } persist(); render(); $('#soxlTradeDialog').close(); });
$('#vrCycleForm').addEventListener('submit', (event) => { event.preventDefault(); const vr = state.investments.tqqqVr; const mode = vr.mode || 'installment'; const flowAmount = mode === 'lump-sum' ? 0 : investmentNumber($('#vrFlowAmount').value); if (mode === 'installment') vr.contribution = flowAmount; if (mode === 'withdrawal') vr.withdrawal = flowAmount; const existing = editingVrCycleId ? vr.cycles.find((item) => item.id === editingVrCycleId) : null; const cycle = { id: existing?.id || createGoalId(), date: $('#vrCycleDate').value, targetValue: investmentNumber($('#vrTargetValue').value), gValue: investmentNumber($('#vrGValue').value), lowerBand: investmentNumber($('#vrLowerBand').value), upperBand: investmentNumber($('#vrUpperBand').value), pool: investmentNumber($('#vrPool').value), shares: investmentNumber($('#vrShares').value), averagePrice: investmentNumber($('#vrAveragePrice').value), currentPrice: investmentNumber($('#vrCurrentPrice').value), flowAmount, note: $('#vrCycleNote').value.trim() }; if (existing) vr.cycles[vr.cycles.findIndex((item) => item.id === existing.id)] = cycle; else vr.cycles.push(cycle); snapshotTqqqVr(`${cycle.date}T21:30:00.000Z`, cycle); persist(); render(); $('#vrCycleDialog').close(); });
$('#vrTradeForm').addEventListener('submit', (event) => { event.preventDefault(); const cycle = currentVrCycle(); if (!cycle) return; const type = $('#vrTradeType').value; const shares = investmentNumber($('#vrTradeShares').value); const price = investmentNumber($('#vrTradePrice').value); if (!shares || !price) return; const position = calculateVrPosition(cycle); if (type === 'sell' && shares > position.shares) { alert('현재 보유 수량보다 많이 매도할 수 없어요.'); return; } cycle.currentPrice = price; cycle.priceUpdatedAt = $('#vrTradeDate').value; const date = $('#vrTradeDate').value; state.investments.tqqqVr.trades.push({ id: createGoalId(), cycleId: cycle.id, date, type, shares, price, note: $('#vrTradeNote').value.trim() }); snapshotTqqqVr(`${date}T21:30:00.000Z`); persist(); render(); $('#vrTradeDialog').close(); });
$('#familyContributionForm').addEventListener('submit', (event) => { event.preventDefault(); const account = activeFamilyAccount(); const amount = investmentNumber($('#familyContributionAmount').value); if (!amount) return; const date = $('#familyContributionDate').value; account.contributed = investmentNumber(account.contributed) + amount; account.cash = investmentNumber(account.cash) + amount; account.contributions.unshift({ id: createGoalId(), date, amount, note: $('#familyContributionNote').value.trim() }); snapshotFamilyAccount(account, `${date}T12:00:00`); persist(); render(); $('#familyContributionDialog').close(); });
$('#familyTradeForm').addEventListener('submit', (event) => { event.preventDefault(); const account = activeFamilyAccount(); const symbol = $('#familyTradeSymbol').value; const type = $('#familyTradeType').value; const shares = investmentNumber($('#familyTradeShares').value); const price = investmentNumber($('#familyTradePrice').value); const amount = shares * price; const holding = account.holdings[symbol]; if (!holding || !shares || !price) return; if (type === 'buy' && amount > investmentNumber(account.cash)) { alert('예수금이 부족해요. 먼저 적립금을 기록해주세요.'); return; } if (type === 'sell' && shares > investmentNumber(holding.shares)) { alert('현재 보유 수량보다 많이 매도할 수 없어요.'); return; } if (type === 'buy') { holding.averagePrice = (investmentNumber(holding.shares) * investmentNumber(holding.averagePrice) + amount) / (investmentNumber(holding.shares) + shares); holding.shares = investmentNumber(holding.shares) + shares; account.cash = investmentNumber(account.cash) - amount; } else { holding.shares = investmentNumber(holding.shares) - shares; account.cash = investmentNumber(account.cash) + amount; if (!holding.shares) holding.averagePrice = 0; } holding.currentPrice = price; const date = $('#familyTradeDate').value; account.trades.unshift({ id: createGoalId(), date, symbol, type, shares, price, amount, note: $('#familyTradeNote').value.trim() }); snapshotFamilyAccount(account, `${date}T12:00:00`); persist(); render(); $('#familyTradeDialog').close(); });
